import{_ as a,o as r,c as i,a0 as l}from"./chunks/framework.jwovEGr5.js";const w=JSON.parse('{"title":"Review Reward Eligibility","description":"","frontmatter":{},"headers":[],"relativePath":"how-to/rewards.md","filePath":"how-to/rewards.md"}'),t={name:"how-to/rewards.md"};function o(s,e,d,n,h,c){return r(),i("div",null,[...e[0]||(e[0]=[l('<h1 id="review-reward-eligibility" tabindex="-1">Review Reward Eligibility <a class="header-anchor" href="#review-reward-eligibility" aria-label="Permalink to &quot;Review Reward Eligibility&quot;">​</a></h1><p>The <strong>Rewards</strong> page is the output step of the rewards workflow. It shows which players match your current reward rules and lets leadership track which cases were already handled.</p><p>This page is for everyone with reward viewing access, including <code>King</code>, <code>Alliance Leader</code>, <code>Co-Leader</code>, and alliance-scoped readers. If you need to change the rules behind the results, go to <a href="./reward-rules.html">Set Up Reward Rules</a>.</p><blockquote><p>Screenshot placeholder: <code>rewards.png</code> (S55)</p></blockquote><h2 id="what-this-page-is-for" tabindex="-1">What this page is for <a class="header-anchor" href="#what-this-page-is-for" aria-label="Permalink to &quot;What this page is for&quot;">​</a></h2><p>Use the Rewards page to:</p><ul><li>see which players are currently eligible</li><li>compare eligible and not-eligible players</li><li>read the rule that matched</li><li>review <a href="./../getting-started/glossary.html#reward-eligibility">reward eligibility</a> details</li><li>mark a reward as handled</li><li>reopen it later if needed</li></ul><p>This page does <strong>not</strong> define the rules. It only shows the results of the rules that were set up in <a href="./reward-rules.html">Reward Rules</a>.</p><h2 id="what-you-will-see" tabindex="-1">What you will see <a class="header-anchor" href="#what-you-will-see" aria-label="Permalink to &quot;What you will see&quot;">​</a></h2><p>The page can include:</p><ul><li>scope selectors for kingdom and alliance</li><li>search</li><li>status and eligibility filters</li><li>sorting options</li><li>top summary cards such as eligible, pending, handled, and average participation</li><li>a rewards table</li></ul><p>Each row can show:</p><ul><li>player name</li><li>matched rule</li><li>whether the player is eligible</li><li>internal points</li><li>participation</li><li>handling status</li><li>player attributes</li><li>notes or reasons</li></ul><h2 id="marking-rewards-as-handled" tabindex="-1">Marking rewards as handled <a class="header-anchor" href="#marking-rewards-as-handled" aria-label="Permalink to &quot;Marking rewards as handled&quot;">​</a></h2><p><code>King</code>, <code>Alliance Leader</code>, and <code>Co-Leader</code> users can usually move a row between <strong>handled</strong> and <strong>open</strong> states.</p><p>That lets the page act as a simple follow-through tracker after prizes, recognition, or other rewards have been given out.</p><h2 id="how-this-connects-to-rules" tabindex="-1">How this connects to rules <a class="header-anchor" href="#how-this-connects-to-rules" aria-label="Permalink to &quot;How this connects to rules&quot;">​</a></h2><p>Think of the workflow in two steps:</p><ol><li><a href="./reward-rules.html">Reward Rules</a> decides the standards.</li><li><strong>Rewards</strong> shows who currently meets them.</li></ol><p>If a result looks wrong, check the rule setup before changing expectations manually.</p><h2 id="good-practice" tabindex="-1">Good practice <a class="header-anchor" href="#good-practice" aria-label="Permalink to &quot;Good practice&quot;">​</a></h2><ul><li>Filter to eligible players first when you are preparing rewards.</li><li>Use handled status so leaders do not duplicate work.</li><li>Re-check the page after major imports or rule changes.</li></ul>',22)])])}const u=a(t,[["render",o]]);export{w as __pageData,u as default};
